const raw = $input.all();

let emails = [];

raw.forEach(item => {
  const dataArray = item.json.data || [];

  dataArray.forEach(d => {
    if (d.line) {
      try {
        const parsed = JSON.parse(d.line);

        emails.push({
          subject: parsed.subject || "",
          body_text: parsed.body_text || ""
        });

      } catch (e) {}
    }
  });
});

if (emails.length < 2) {
  return [
    {
      json: {
        message: "Pas assez d'emails pour calculer une similarité",
        count: emails.length
      }
    }
  ];
}

function tokenize(text) {
  if (!text) return [];

  return text
    .toLowerCase()
    .replace(/[^\w\s]/g, "")
    .split(/\s+/)
    .filter(Boolean);
}

function buildVocabulary(docs) {
  const vocab = new Set();

  docs.forEach(doc => {
    tokenize(doc).forEach(word => vocab.add(word));
  });

  return Array.from(vocab);
}

function textToVector(text, vocab) {
  const words = tokenize(text);

  const freq = {};
  words.forEach(w => {
    freq[w] = (freq[w] || 0) + 1;
  });

  return vocab.map(word => freq[word] || 0);
}

function dot(a, b) {
  return a.reduce((sum, v, i) => sum + v * b[i], 0);
}

function magnitude(v) {
  return Math.sqrt(v.reduce((s, x) => s + x * x, 0));
}

function cosine(a, b) {
  const denom = magnitude(a) * magnitude(b);
  if (!denom) return 0;
  return dot(a, b) / denom;
}

const vocab = buildVocabulary(emails.map(e => e.body_text));

const vectors = emails.map(e => textToVector(e.body_text, vocab));

const avgVector = [];

for (let i = 0; i < vocab.length; i++) {
  let sum = 0;

  for (let j = 0; j < vectors.length; j++) {
    sum += vectors[j][i];
  }

  avgVector.push(sum / vectors.length);
}

const results = emails.map((email, i) => {
  const vec = vectors[i];
  const similarity = cosine(vec, avgVector);

  return {
    json: {
      subject: email.subject,
      body_text: email.body_text,
      similarity: Number(similarity.toFixed(2))
    }
  };
});

results.sort((a, b) => b.json.similarity - a.json.similarity);

return results;

